impl Solution { pub fn minimum_operations_to_make_k_periodic(black_word: String, black_k: i32) -> i32 { let (black_n, black_k) = (black_word.len(), black_k as usize); let mut black_map = std::collections::HashMap::new(); for i in (0..black_n).step_by(black_k) { *black_map.entry(&black_word[i..i+black_k]).or_insert(0) += 1; } let black_max = black_map.values().max().unwrap(); (black_n / black_k) as i32 - black_max } }